}

import { GoogleGenAI, Type } from "@google/genai";
import { Estimation, RoundStats } from "../types";

export const analyzeConsensus = async (
  estimations: Estimation[],
  stats: RoundStats,
  unit: string
): Promise<{ level: 'Alta' | 'Media' | 'Baja'; recommendation: string; aiInsights: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Como experto facilitador del Método Wideband Delphi, analiza la siguiente ronda de estimación:

    Unidad de medida: ${unit}
    Estadísticas:
    - Media: ${stats.mean}
    - Mediana: ${stats.median}
    - Desviación Estándar: ${stats.stdDev}
    - Coeficiente de Variación: ${stats.coefficientOfVariation}%

    Justificaciones de los expertos:
    ${estimations.map(e => `- Valor: ${e.value}. Justificación: "${e.justification}"`).join('\n')}

    Por favor, proporciona:
    1. Nivel de convergencia (Alta, Media, Baja).
    2. Recomendación (Abrir nueva ronda o Finalizar).
    3. Un breve resumen (Insights) sobre por qué hay desacuerdo o qué puntos clave deben discutirse.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            level: { type: Type.STRING, description: 'Alta, Media o Baja' },
            recommendation: { type: Type.STRING, description: 'Siguiente paso sugerido' },
            aiInsights: { type: Type.STRING, description: 'Resumen analítico' }
          },
          required: ["level", "recommendation", "aiInsights"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result;
  } catch (error) {
    console.error("Error analyzing consensus with Gemini:", error);
    return {
      level: stats.coefficientOfVariation < 15 ? 'Alta' : stats.coefficientOfVariation < 30 ? 'Media' : 'Baja',
      recommendation: stats.coefficientOfVariation < 20 ? 'Finalizar sesión' : 'Abrir nueva ronda de discusión',
      aiInsights: "Análisis automatizado basado en métricas estadísticas básicas (CV)."
    };
  }
};

import { Estimation, RoundStats } from '../types';

export const calculateRoundStats = (estimations: Estimation[]): RoundStats => {
  const values = estimations.map(e => e.value).sort((a, b) => a - b);
  const n = values.length;

  if (n === 0) return {
    mean: 0, median: 0, stdDev: 0, variance: 0, 
    coefficientOfVariation: 0, range: [0, 0], iqr: 0, outliers: []
  };

  const sum = values.reduce((a, b) => a + b, 0);
  const mean = sum / n;

  const median = n % 2 !== 0 
    ? values[Math.floor(n / 2)] 
    : (values[n / 2 - 1] + values[n / 2]) / 2;

  const variance = values.reduce((acc, val) => acc + Math.pow(val - mean, 2), 0) / n;
  const stdDev = Math.sqrt(variance);
  const cv = (stdDev / mean) * 100;

  // IQR Outlier Detection
  const q1 = values[Math.floor(n * 0.25)];
  const q3 = values[Math.floor(n * 0.75)];
  const iqr = q3 - q1;
  const lowerBound = q1 - 1.5 * iqr;
  const upperBound = q3 + 1.5 * iqr;

  const outliers = estimations
    .filter(e => e.value < lowerBound || e.value > upperBound)
    .map(e => e.id);

  return {
    mean: Number(mean.toFixed(2)),
    median: Number(median.toFixed(2)),
    stdDev: Number(stdDev.toFixed(2)),
    variance: Number(variance.toFixed(2)),
    coefficientOfVariation: Number(cv.toFixed(2)),
    range: [values[0], values[n - 1]],
    iqr: Number(iqr.toFixed(2)),
    outliers
  };
};

