import React, { useState, useEffect } from 'react';
import { 
  Plus, 
  Send, 
  Lock, 
  Eye, 
  LineChart, 
  MessageCircle, 
  Sparkles,
  TrendingDown,
  History,
  Info
} from 'lucide-react';
import { Estimation, Round, RoundStats, ConvergenceAnalysis } from '../types';
import { calculateRoundStats } from '../utils/statistics';
import { analyzeConsensus } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart as RechartsLineChart, Line } from 'recharts';

interface EstimationRoundsProps {
  taskId: string;
  taskTitle: string;
  unit: string;
}

const EstimationRounds: React.FC<EstimationRoundsProps> = ({ taskId, taskTitle, unit }) => {
  const [rounds, setRounds] = useState<Round[]>([]);
  const [activeRound, setActiveRound] = useState<Round | null>(null);
  const [estimations, setEstimations] = useState<Estimation[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [justification, setJustification] = useState('');
  const [analysis, setAnalysis] = useState<ConvergenceAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Initialize with a mock first round if empty
  useEffect(() => {
    const r1: Round = {
      id: 'r1',
      taskId,
      roundNumber: 1,
      status: 'Abierta',
      startTime: Date.now()
    };
    setRounds([r1]);
    setActiveRound(r1);
  }, [taskId]);

  const handleSubmitEstimate = () => {
    if (!activeRound || !inputValue) return;

    const newEst: Estimation = {
      id: Math.random().toString(36).substr(2, 9),
      roundId: activeRound.id,
      taskId,
      expertId: 'u1', // In real app, from auth
      value: Number(inputValue),
      justification,
      timestamp: Date.now()
    };

    setEstimations(prev => [...prev, newEst]);
    setInputValue('');
    setJustification('');
  };

  const handleCloseRound = async () => {
    if (!activeRound) return;

    const stats = calculateRoundStats(estimations.filter(e => e.roundId === activeRound.id));

    const updatedRound: Round = {
      ...activeRound,
      status: 'Cerrada',
      endTime: Date.now(),
      stats
    };

    setRounds(prev => prev.map(r => r.id === activeRound.id ? updatedRound : r));
    setActiveRound(null);

    // AI Analysis
    setIsAnalyzing(true);
    const aiResult = await analyzeConsensus(estimations.filter(e => e.roundId === activeRound.id), stats, unit);
    setAnalysis(aiResult);
    setIsAnalyzing(false);
  };

  const handleStartNextRound = () => {
    const nextRoundNumber = rounds.length + 1;
    const nextRound: Round = {
      id: `r${nextRoundNumber}`,
      taskId,
      roundNumber: nextRoundNumber,
      status: 'Abierta',
      startTime: Date.now()
    };
    setRounds(prev => [...prev, nextRound]);
    setActiveRound(nextRound);
    setAnalysis(null);
  };

  // Chart data
  const chartData = estimations
    .filter(e => e.roundId === rounds[rounds.length - 1]?.id)
    .reduce((acc: any[], curr) => {
      const existing = acc.find(a => a.name === curr.value);
      if (existing) existing.count += 1;
      else acc.push({ name: curr.value, count: 1 });
      return acc;
    }, [])
    .sort((a, b) => a.name - b.name);

  return (
    <div className="space-y-6">
      {/* Header Info */}
      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
        <div>
          <h3 className="text-xl font-bold text-slate-900">{taskTitle}</h3>
          <p className="text-sm text-slate-500">Sesión de estimación iterativa</p>
        </div>
        <div className="flex items-center gap-2">
          {rounds.map(r => (
            <div 
              key={r.id} 
              className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm border-2 ${
                r.status === 'Abierta' ? 'bg-indigo-50 border-indigo-500 text-indigo-600' : 'bg-slate-100 border-slate-200 text-slate-400'
              }`}
            >
              R{r.roundNumber}
            </div>
          ))}
          {activeRound === null && (
            <button 
              onClick={handleStartNextRound}
              className="w-10 h-10 rounded-full bg-slate-50 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 hover:text-indigo-500 hover:border-indigo-400 hover:bg-indigo-50 transition-all"
            >
              <Plus className="w-5 h-5" />
            </button>
          )}
        </div>
      </div>

      {activeRound && (
        <div className="bg-indigo-600 rounded-2xl p-8 text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
          <div className="relative z-10 space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <h4 className="text-2xl font-bold">Ronda {activeRound.roundNumber} en curso</h4>
                <p className="text-indigo-100 mt-1">Registra tu estimación individual de forma anónima.</p>
              </div>
              <Lock className="w-8 h-8 opacity-40" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="md:col-span-1">
                <label className="block text-sm font-semibold mb-2 text-indigo-100">Estimación ({unit})</label>
                <input 
                  type="number" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder="Ej: 12"
                  className="w-full bg-indigo-500 border border-indigo-400 rounded-xl px-4 py-3 text-white placeholder-indigo-300 focus:outline-none focus:ring-2 focus:ring-indigo-300 transition-all"
                />
              </div>
              <div className="md:col-span-3">
                <label className="block text-sm font-semibold mb-2 text-indigo-100">Justificación técnica</label>
                <div className="flex gap-3">
                  <input 
                    type="text" 
                    value={justification}
                    onChange={(e) => setJustification(e.target.value)}
                    placeholder="¿Por qué este valor?"
                    className="flex-1 bg-indigo-500 border border-indigo-400 rounded-xl px-4 py-3 text-white placeholder-indigo-300 focus:outline-none focus:ring-2 focus:ring-indigo-300 transition-all"
                  />
                  <button 
                    onClick={handleSubmitEstimate}
                    className="bg-white text-indigo-600 px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-50 transition-all active:scale-95"
                  >
                    <Send className="w-5 h-5" />
                    Enviar
                  </button>
                </div>
              </div>
            </div>
          </div>
          {/* Decorative Circle */}
          <div className="absolute -bottom-12 -right-12 w-48 h-48 bg-indigo-500 rounded-full opacity-20" />
        </div>
      )}

      {/* Results Section */}
      {!activeRound && rounds.length > 0 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Stats Card */}
            <div className="lg:col-span-1 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
              <h4 className="font-bold text-slate-900 flex items-center gap-2">
                <LineChart className="w-5 h-5 text-indigo-500" />
                Resumen Estadístico
              </h4>

              {rounds[rounds.length - 1].stats ? (
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-3 rounded-xl">
                      <p className="text-[10px] uppercase font-bold text-slate-500">Media</p>
                      <p className="text-xl font-bold">{rounds[rounds.length - 1].stats?.mean}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl">
                      <p className="text-[10px] uppercase font-bold text-slate-500">Mediana</p>
                      <p className="text-xl font-bold">{rounds[rounds.length - 1].stats?.median}</p>
                    </div>
                  </div>
                  <div className="p-4 rounded-xl border border-slate-100 flex items-center justify-between">
                    <div>
                      <p className="text-xs font-semibold text-slate-500">Coef. Variación</p>
                      <p className={`text-lg font-bold ${(rounds[rounds.length-1].stats?.coefficientOfVariation ?? 0) < 20 ? 'text-emerald-600' : 'text-rose-500'}`}>
                        {rounds[rounds.length - 1].stats?.coefficientOfVariation}%
                      </p>
                    </div>
                    <TrendingDown className={`w-6 h-6 ${(rounds[rounds.length-1].stats?.coefficientOfVariation ?? 0) < 20 ? 'text-emerald-500' : 'text-rose-400 opacity-50'}`} />
                  </div>
                  <div className="p-3 bg-slate-50 rounded-xl text-xs">
                    <span className="font-bold text-slate-500">Rango:</span> 
                    <span className="ml-2 font-mono">{rounds[rounds.length - 1].stats?.range[0]} - {rounds[rounds.length - 1].stats?.range[1]} {unit}</span>
                  </div>
                </div>
              ) : (
                <div className="text-slate-400 italic text-sm">Cierra la ronda para ver estadísticas.</div>
              )}
            </div>

            {/* Distribution Chart */}
            <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col">
              <h4 className="font-bold text-slate-900 mb-6 flex items-center gap-2">
                <Eye className="w-5 h-5 text-indigo-500" />
                Distribución de Estimaciones
              </h4>
              <div className="flex-1 min-h-[200px]">
                {chartData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" fontSize={12} stroke="#64748b" />
                      <YAxis allowDecimals={false} fontSize={12} stroke="#64748b" />
                      <Tooltip 
                        contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                        cursor={{ fill: '#f8fafc' }}
                      />
                      <Bar dataKey="count" fill="#4f46e5" radius={[4, 4, 0, 0]} barSize={40} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">
                    Esperando datos de la ronda...
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* AI Recommendation Panel */}
          <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-6 relative overflow-hidden">
            <div className="relative z-10 flex items-start gap-6">
              <div className="bg-white p-3 rounded-2xl shadow-sm border border-indigo-100">
                <Sparkles className="w-8 h-8 text-indigo-600" />
              </div>
              <div className="flex-1 space-y-2">
                <div className="flex items-center gap-3">
                  <h4 className="text-indigo-900 font-bold text-lg">Recomendación DelphiPro (IA)</h4>
                  {isAnalyzing ? (
                    <span className="flex items-center gap-2 text-xs font-bold text-indigo-500 animate-pulse">
                      Analizando convergencia...
                    </span>
                  ) : analysis && (
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-full ${
                      analysis.level === 'Alta' ? 'bg-emerald-500 text-white' : 
                      analysis.level === 'Media' ? 'bg-amber-500 text-white' : 'bg-rose-500 text-white'
                    }`}>
                      Convergencia {analysis.level}
                    </span>
                  )}
                </div>
                {analysis ? (
                  <div className="space-y-4">
                    <p className="text-indigo-800 text-sm leading-relaxed">{analysis.aiInsights}</p>
                    <div className="flex items-center gap-3 bg-white/50 p-3 rounded-xl border border-indigo-100/50">
                      <div className="bg-indigo-600 text-white text-[10px] font-bold px-2 py-0.5 rounded-md">TIP</div>
                      <p className="text-indigo-700 text-sm font-semibold">{analysis.recommendation}</p>
                    </div>
                  </div>
                ) : (
                  <p className="text-indigo-400 text-sm italic">Cierra la ronda para obtener recomendaciones inteligentes.</p>
                )}
              </div>
            </div>
          </div>

          {/* Justifications Feed */}
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-50 flex items-center justify-between">
              <h4 className="font-bold flex items-center gap-2">
                <MessageCircle className="w-5 h-5 text-indigo-500" />
                Discusión Anónima
              </h4>
              <span className="text-xs text-slate-400 font-medium">{estimations.filter(e => e.roundId === rounds[rounds.length-1].id).length} participaciones</span>
            </div>
            <div className="p-6 space-y-4 max-h-96 overflow-y-auto">
              {estimations.filter(e => e.roundId === rounds[rounds.length-1].id).map((est, i) => (
                <div key={est.id} className="flex gap-4 p-4 rounded-xl hover:bg-slate-50 transition-colors group">
                  <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-500 shrink-0">
