                  </div>
                  <div className="flex-1">
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-sm font-bold text-indigo-600">Estimó {est.value} {unit}</span>
                      <span className="text-[10px] text-slate-400 font-medium">Hace 2 min</span>
                    </div>
                    <p className="text-sm text-slate-600 italic">"{est.justification}"</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Footer Controls */}
      {activeRound && (
        <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between sticky bottom-4 z-20">
          <div className="flex items-center gap-3">
             <div className="flex -space-x-2">
                {[1,2,3].map(i => (
                  <div key={i} className="w-8 h-8 rounded-full border-2 border-white bg-slate-200 flex items-center justify-center text-[10px] font-bold text-slate-500">U{i}</div>
                ))}
             </div>
             <p className="text-xs font-medium text-slate-500">Expertos participando: 3/5</p>
          </div>
          <button 
            onClick={handleCloseRound}
            className="bg-slate-900 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-black transition-all active:scale-95 shadow-lg shadow-slate-200"
          >
            Cerrar Ronda
          </button>
        </div>
      )}
    </div>
  );
};

