               </div>
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 ml-1">Descripción del Objetivo</label>
                  <textarea 
                    required
                    rows={4}
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Describe el alcance técnico a estimar..."
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2rem] px-6 py-4 text-sm font-medium focus:ring-2 focus:ring-delphi-keppel/30 focus:border-delphi-keppel/30 transition-all outline-none"
                  />
               </div>
               <button type="button" onClick={() => setStep(2)} className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all">Siguiente</button>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
               <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 ml-1">Unidad de Estimación (RF006)</label>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {['Horas', 'Puntos de Historia', 'Días Persona'].map(u => (
                      <button 
                        key={u}
                        type="button"
                        onClick={() => setUnit(u as any)}
                        className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-center gap-4 ${unit === u ? 'border-delphi-keppel bg-delphi-keppel/5 text-delphi-keppel shadow-xl shadow-delphi-keppel/5' : 'border-slate-100 bg-white text-slate-400 hover:border-slate-200'}`}
                      >
                        <div className={`p-3 rounded-2xl ${unit === u ? 'bg-delphi-keppel text-white' : 'bg-slate-50 text-slate-400'}`}>
                          <Plus className="w-6 h-6" />
                        </div>
                        <span className="font-black text-[10px] uppercase tracking-widest">{u}</span>
                      </button>
                    ))}
                  </div>
               </div>
               <div className="flex gap-4">
                 <button type="button" onClick={() => setStep(1)} className="px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-all">Atrás</button>
                 <button type="button" onClick={() => setStep(3)} className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all">Siguiente</button>
               </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
               <div className="bg-delphi-vanilla/40 p-8 rounded-[2rem] border-2 border-dashed border-delphi-vanilla flex flex-col items-center text-center gap-6">
                  <div className="bg-white p-4 rounded-full shadow-lg">
                    <Users className="w-10 h-10 text-delphi-orange" />
                  </div>
                  <div>
                    <h4 className="font-black text-slate-900">Asignar Panel de Expertos</h4>
                    <p className="text-sm text-slate-500 font-medium">Se enviará una invitación automática a los 5 expertos preconfigurados para este equipo.</p>
                  </div>
                  <div className="flex -space-x-3">
                    {[1,2,3,4,5].map(i => (
                      <div key={i} className="w-12 h-12 rounded-full border-4 border-white bg-slate-200 flex items-center justify-center text-xs font-black text-slate-400">EX</div>
                    ))}
                  </div>
               </div>
               <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex items-start gap-4">
                  <Shield className="w-6 h-6 text-delphi-keppel shrink-0 mt-1" />
                  <p className="text-xs text-slate-500 font-medium leading-relaxed">
                    Al confirmar, el proyecto pasará a estado <strong>Kickoff</strong> y se habilitará la subida de documentación técnica.
                  </p>
               </div>
               <div className="flex gap-4">
                 <button type="button" onClick={() => setStep(2)} className="px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-all">Atrás</button>
                 <button type="submit" className="bg-delphi-keppel text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-delphi-keppel/20 hover:scale-105 transition-all flex items-center gap-2">
                   <Send className="w-4 h-4" /> Finalizar y Abrir Sesión
                 </button>
               </div>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default ProjectForm;

import React, { useState, useEffect } from 'react';
import { 
  Plus, 
  Send, 
  Lock, 
  Eye, 
  LineChart, 
  MessageCircle, 
  Sparkles,
  TrendingDown,
  Info,
  History,
  TrendingUp
} from 'lucide-react';
import { Estimation, Round, ConvergenceAnalysis } from '../types';
import { calculateRoundStats } from '../utils/statistics';
import { analyzeConsensus } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart as ReLineChart, Line } from 'recharts';

interface EstimationRoundsProps {
  taskId: string;
  taskTitle: string;
  unit: string;
}

const EstimationRounds: React.FC<EstimationRoundsProps> = ({ taskId, taskTitle, unit }) => {
  const [rounds, setRounds] = useState<Round[]>([]);
  const [activeRound, setActiveRound] = useState<Round | null>(null);
  const [estimations, setEstimations] = useState<Estimation[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [justification, setJustification] = useState('');
  const [analysis, setAnalysis] = useState<ConvergenceAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showEvolution, setShowEvolution] = useState(false);

  useEffect(() => {
    const r1: Round = {
      id: 'r1',
      taskId,
      roundNumber: 1,
      status: 'Abierta',
      startTime: Date.now()
    };
    setRounds([r1]);
    setActiveRound(r1);
  }, [taskId]);

  const handleSubmitEstimate = () => {
    if (!activeRound || !inputValue) return;

    const newEst: Estimation = {
      id: Math.random().toString(36).substr(2, 9),
      roundId: activeRound.id,
      taskId,
      expertId: 'u1',
      value: Number(inputValue),
      justification,
      timestamp: Date.now()
    };

    setEstimations(prev => [...prev, newEst]);
    setInputValue('');
    setJustification('');
  };

  const handleCloseRound = async () => {
    if (!activeRound) return;

    const roundEstimations = estimations.filter(e => e.roundId === activeRound.id);
    const stats = calculateRoundStats(roundEstimations);

    const updatedRound: Round = {
      ...activeRound,
      status: 'Cerrada',
      endTime: Date.now(),
      stats
    };

    setRounds(prev => prev.map(r => r.id === activeRound.id ? updatedRound : r));
    setActiveRound(null);

    setIsAnalyzing(true);
    const aiResult = await analyzeConsensus(roundEstimations, stats, unit);
    setAnalysis(aiResult);
    setIsAnalyzing(false);
  };

  const handleStartNextRound = () => {
    const nextRoundNumber = rounds.length + 1;
    const nextRound: Round = {
      id: `r${nextRoundNumber}`,
      taskId,
      roundNumber: nextRoundNumber,
      status: 'Abierta',
      startTime: Date.now()
    };
    setRounds(prev => [...prev, nextRound]);
    setActiveRound(nextRound);
    setAnalysis(null);
  };

  const currentRoundEstimations = estimations.filter(e => 
    e.roundId === (activeRound ? activeRound.id : rounds[rounds.length - 1]?.id)
  );

  const distributionData = currentRoundEstimations
    .reduce((acc: any[], curr) => {
      const existing = acc.find(a => a.name === curr.value);
      if (existing) existing.count += 1;
      else acc.push({ name: curr.value, count: 1 });
      return acc;
    }, [])
    .sort((a, b) => a.name - b.name);

  // RF018: Evolución de métricas
  const evolutionData = rounds
    .filter(r => r.status === 'Cerrada' && r.stats)
    .map(r => ({
      name: `R${r.roundNumber}`,
      media: r.stats?.mean,
      desviacion: r.stats?.stdDev
    }));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Round Selector / Progress */}
      <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="bg-delphi-keppel/10 p-3 rounded-2xl">
             <LineChart className="w-6 h-6 text-delphi-keppel" />
          </div>
          <div>
            <h3 className="text-xl font-black text-slate-900">{taskTitle}</h3>
            <p className="text-sm font-bold text-slate-400">Proceso Iterativo Wideband Delphi</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            {rounds.map(r => (
              <div 
                key={r.id} 
                className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-sm transition-all border-2 ${
                  r.status === 'Abierta' 
                    ? 'bg-delphi-keppel text-white border-delphi-keppel shadow-lg shadow-delphi-keppel/20' 
                    : 'bg-white border-slate-100 text-slate-300'
                }`}
              >
                R{r.roundNumber}
              </div>
            ))}
            {!activeRound && (
              <button 
                onClick={handleStartNextRound}
                className="w-12 h-12 rounded-2xl bg-slate-50 border-2 border-dashed border-slate-200 flex items-center justify-center text-slate-400 hover:text-delphi-keppel hover:border-delphi-keppel/50 hover:bg-delphi-keppel/5 transition-all"
              >
                <Plus className="w-6 h-6" />
              </button>
            )}
          </div>
          <div className="h-8 w-px bg-slate-200" />
          <button 
            onClick={() => setShowEvolution(!showEvolution)}
            className={`p-3 rounded-xl border-2 transition-all ${showEvolution ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'}`}
          >
            <History className="w-5 h-5" />
          </button>
        </div>
      </div>

      {showEvolution && (
        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm animate-in zoom-in-95 duration-300">
           <div className="flex items-center justify-between mb-10">
              <h4 className="text-xl font-black text-slate-900 flex items-center gap-3">
                 <TrendingUp className="w-6 h-6 text-delphi-keppel" />
                 Evolución de la Convergencia (RF018)
              </h4>
              <p className="text-xs font-black uppercase text-slate-400 tracking-widest">Trazabilidad por Rondas</p>
           </div>
           <div className="h-64 w-full">
              {evolutionData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <ReLineChart data={evolutionData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" stroke="#cbd5e1" fontSize={12} fontWeight="bold" />
                    <YAxis stroke="#cbd5e1" fontSize={12} fontWeight="bold" />
                    <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                    <Line type="monotone" dataKey="media" stroke="#2BBAA5" strokeWidth={4} dot={{ r: 6, fill: '#2BBAA5' }} name="Media" />
                    <Line type="monotone" dataKey="desviacion" stroke="#F96635" strokeWidth={3} strokeDasharray="5 5" dot={{ r: 4, fill: '#F96635' }} name="Desviación Estándar" />
                  </ReLineChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 italic text-sm">
                   Cierra al menos una ronda para visualizar la tendencia.
                </div>
              )}
           </div>
        </div>
      )}

      {activeRound ? (
        <div className="bg-gradient-delphi rounded-[2.5rem] p-10 text-white shadow-2xl shadow-delphi-keppel/20 relative overflow-hidden">
          <div className="relative z-10 space-y-8">
            <div className="flex items-center justify-between">
              <div>
                <span className="bg-white/20 px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest mb-4 inline-block">Fase de Estimación</span>
                <h4 className="text-4xl font-black">Ronda {activeRound.roundNumber}</h4>
                <p className="text-delphi-celadon mt-2 font-bold text-lg max-w-lg">
                  Tu participación es anónima. Describe técnicamente por qué asignas este valor.
                </p>
              </div>
              <div className="hidden md:flex items-center gap-3 bg-white/10 p-4 rounded-[2rem] border border-white/10 backdrop-blur-sm">
                 <Lock className="w-10 h-10 text-white/50" />
                 <div className="text-left">
                   <p className="text-[10px] font-black uppercase opacity-60">Privacidad</p>
                   <p className="text-xs font-bold">Encripción Activa</p>
                 </div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 items-end">
              <div className="lg:col-span-1">
                <label className="block text-xs font-black uppercase tracking-widest mb-3 opacity-80">Valor ({unit})</label>
                <input 
                  type="number" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder="Ej: 16"
                  className="w-full bg-white/10 border-2 border-white/20 rounded-2xl px-6 py-4 text-2xl font-black placeholder-white/30 focus:outline-none focus:bg-white/20 focus:border-white/50 transition-all text-white"
                />
              </div>
              <div className="lg:col-span-2">
                <label className="block text-xs font-black uppercase tracking-widest mb-3 opacity-80">Justificación Técnica</label>
                <textarea 
                  value={justification}
                  onChange={(e) => setJustification(e.target.value)}
                  placeholder="Detalla riesgos, complejidad o dependencias..."
                  rows={1}
                  className="w-full bg-white/10 border-2 border-white/20 rounded-2xl px-6 py-4 text-white placeholder-white/30 focus:outline-none focus:bg-white/20 focus:border-white/50 transition-all font-medium"
                />
              </div>
              <div className="lg:col-span-1">
                <button 
                  onClick={handleSubmitEstimate}
                  className="w-full bg-white text-delphi-keppel px-8 py-4 rounded-2xl font-black flex items-center justify-center gap-3 hover:scale-105 active:scale-95 transition-all shadow-xl shadow-black/10"
                >
                  <Send className="w-5 h-5" />
                  Enviar
                </button>
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Analysis Dashboard */}
            <div className="lg:col-span-1 bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm space-y-8">
              <h4 className="font-black text-slate-900 flex items-center gap-3 text-lg">
                <LineChart className="w-6 h-6 text-delphi-keppel" />
                Estadísticas
              </h4>

              {rounds[rounds.length - 1].stats ? (
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-delphi-vanilla/30 p-4 rounded-2xl border border-delphi-vanilla">
                      <p className="text-[10px] uppercase font-black text-delphi-orange tracking-widest">Media</p>
                      <p className="text-3xl font-black text-slate-900">{rounds[rounds.length - 1].stats?.mean}</p>
                    </div>
                    <div className="bg-delphi-celadon/10 p-4 rounded-2xl border border-delphi-celadon/20">
                      <p className="text-[10px] uppercase font-black text-delphi-keppel tracking-widest">Mediana</p>
                      <p className="text-3xl font-black text-slate-900">{rounds[rounds.length - 1].stats?.median}</p>
                    </div>
                  </div>
                  <div className="p-5 rounded-2xl border border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Convergencia (CV)</p>
                      <p className={`text-2xl font-black mt-1 ${(rounds[rounds.length-1].stats?.coefficientOfVariation ?? 0) < 15 ? 'text-delphi-keppel' : 'text-delphi-orange'}`}>
                        {rounds[rounds.length - 1].stats?.coefficientOfVariation}%
                      </p>
                    </div>
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center ${(rounds[rounds.length-1].stats?.coefficientOfVariation ?? 0) < 15 ? 'bg-delphi-keppel/10 text-delphi-keppel' : 'bg-delphi-orange/10 text-delphi-orange'}`}>
                      <TrendingDown className="w-6 h-6" />
                    </div>
                  </div>
                </div>
              ) : (
                <div className="p-8 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200 text-center">
                   <p className="text-slate-400 font-bold italic text-sm">Sin datos calculados</p>
                </div>
              )}
            </div>

            {/* Visual Distribution */}
            <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col min-h-[350px]">
              <h4 className="font-black text-slate-900 mb-8 flex items-center gap-3 text-lg">
                <Eye className="w-6 h-6 text-delphi-keppel" />
                Dispersión de Valores
              </h4>
              <div className="flex-1 w-full">
                {distributionData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={distributionData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" fontSize={12} stroke="#cbd5e1" fontWeight="bold" />
                      <YAxis allowDecimals={false} fontSize={12} stroke="#cbd5e1" fontWeight="bold" />
                      <Tooltip 
                        contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                        cursor={{ fill: '#f8fafc' }}
                      />
                      <Bar dataKey="count" fill="#2BBAA5" radius={[12, 12, 0, 0]} barSize={50} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4">
                    <Info className="w-12 h-12 opacity-20" />
                    <p className="font-bold italic">Esperando visualización...</p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* AI Insights */}
          <div className="bg-white border-2 border-delphi-keppel/20 rounded-[2.5rem] p-10 shadow-xl shadow-delphi-keppel/5 relative overflow-hidden group">
            <div className="relative z-10 flex flex-col md:flex-row gap-10 items-center">
              <div className="bg-delphi-keppel p-6 rounded-[2rem] shadow-xl shadow-delphi-keppel/30 group-hover:rotate-6 transition-transform">
                <Sparkles className="w-12 h-12 text-white" />
              </div>
              <div className="flex-1 space-y-4">
                <div className="flex flex-wrap items-center gap-4">
                  <h4 className="text-2xl font-black text-slate-900 tracking-tight">Análisis Inteligente de Consenso</h4>
                  {isAnalyzing ? (
                    <span className="flex items-center gap-2 text-xs font-black text-delphi-keppel bg-delphi-keppel/10 px-4 py-1.5 rounded-full animate-pulse border border-delphi-keppel/20">
                      PROCESANDO NEURONAS...
                    </span>
                  ) : analysis && (
                    <span className={`text-[10px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full border shadow-sm ${
                      analysis.level === 'Alta' ? 'bg-delphi-keppel text-white border-delphi-keppel' : 
                      analysis.level === 'Media' ? 'bg-delphi-orange text-white border-delphi-orange' : 'bg-delphi-giants text-white border-delphi-giants'
                    }`}>
                      Convergencia {analysis.level}
                    </span>
                  )}
                </div>
                {analysis ? (
                  <div className="space-y-6">
                    <p className="text-slate-600 text-lg leading-relaxed font-medium">"{analysis.aiInsights}"</p>
                    <div className="flex items-center gap-4 bg-delphi-vanilla/50 p-6 rounded-3xl border border-delphi-vanilla/50">
                      <div className="bg-delphi-giants text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest">Recomendación</div>
                      <p className="text-slate-900 font-black text-lg">{analysis.recommendation}</p>
                    </div>
                  </div>
                ) : (
                  <p className="text-slate-400 font-bold italic text-lg">Cierra la ronda para desbloquear el análisis profundo de la IA.</p>
                )}
              </div>
            </div>
          </div>

          {/* Justifications */}
          <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
              <h4 className="text-xl font-black flex items-center gap-3">
                <MessageCircle className="w-6 h-6 text-delphi-keppel" />
                Justificaciones Anónimas
              </h4>
              <span className="text-xs font-black text-delphi-keppel bg-delphi-keppel/10 px-4 py-1.5 rounded-full uppercase tracking-widest">
                {currentRoundEstimations.length} Expertos
              </span>
            </div>
            <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
              {currentRoundEstimations.map((est, i) => (
                <div key={est.id} className="p-6 rounded-3xl bg-slate-50 border border-slate-100 hover:border-delphi-keppel/30 transition-all group">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 rounded-2xl bg-white border border-slate-200 flex items-center justify-center font-black text-slate-400 group-hover:text-delphi-keppel group-hover:border-delphi-keppel/30 transition-all shadow-sm">
                      E{i + 1}
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Estimación</p>
                      <p className="text-xl font-black text-delphi-keppel">{est.value} {unit}</p>
                    </div>
                  </div>
                  <p className="text-slate-600 font-medium leading-relaxed italic border-l-4 border-delphi-keppel/20 pl-4 py-1">
                    "{est.justification || 'Sin comentario detallado.'}"
                  </p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Facilitator Controls Sticky Bar */}
      {activeRound && (
        <div className="bg-white/80 backdrop-blur-md p-5 rounded-[2.5rem] border border-white shadow-2xl flex items-center justify-between sticky bottom-8 z-40 max-w-4xl mx-auto ring-1 ring-black/5">
          <div className="flex items-center gap-6 px-4">
             <div className="flex -space-x-3">
                {[1,2,3].map(i => (
