                <div className="flex items-center justify-between mb-8">
                   <h3 className="font-black text-xl tracking-tight">Carga de Tareas</h3>
                   <div className="bg-slate-50 px-3 py-1.5 rounded-xl border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                     {tasks.length} items
                   </div>
                </div>

                <div className="space-y-4">
                  {tasks.map(task => (
                    <button
                      key={task.id}
                      onClick={() => setSelectedTaskId(task.id)}
                      className={`w-full text-left p-6 rounded-[2rem] border-2 transition-all ${
                        selectedTaskId === task.id 
                          ? 'border-delphi-keppel bg-delphi-keppel/[0.03] shadow-lg shadow-delphi-keppel/5' 
                          : 'border-slate-50 bg-slate-50/30 hover:border-slate-200 hover:bg-white'
                      }`}
                    >
                      <div className="flex items-start gap-5">
                        <div className={`shrink-0 mt-1 transition-colors ${selectedTaskId === task.id ? 'text-delphi-keppel' : 'text-slate-300'}`}>
                          {task.finalEstimate ? <CheckCircle2 className="w-7 h-7" /> : <Circle className="w-7 h-7" />}
                        </div>
                        <div className="flex-1">
                          <h4 className={`text-base font-black leading-tight mb-2 ${selectedTaskId === task.id ? 'text-slate-900' : 'text-slate-500 font-bold'}`}>
                            {task.title}
                          </h4>
                          {task.finalEstimate ? (
                            <div className="flex items-center gap-2 text-delphi-keppel">
                               <Award className="w-4 h-4" />
                               <span className="text-xs font-black uppercase tracking-widest">Consenso: {task.finalEstimate}h</span>
                            </div>
                          ) : (
                            <div className="space-y-2 mt-3">
                               <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                                  <div className={`h-full bg-delphi-keppel transition-all duration-1000 ${selectedTaskId === task.id ? 'w-2/3' : 'w-0'}`}></div>
                               </div>
                               <div className="flex items-center justify-between">
                                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Progreso</span>
                                  <span className="text-[10px] font-black text-delphi-keppel uppercase tracking-widest">66%</span>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {isFacilitator && (
                <div className="bg-delphi-vanilla p-8 rounded-[3rem] border border-delphi-orange/20 relative overflow-hidden group">
                  <div className="relative z-10">
                     <h4 className="flex items-center gap-3 text-delphi-orange font-black mb-4 text-base">
                       <AlertCircle className="w-6 h-6" />
                       Control de Facilitador
                     </h4>
                     <p className="text-sm text-slate-700 leading-relaxed font-bold">
                       Supervisa el flujo de estimaciones y cierra las rondas una vez alcances el consenso deseado (CV &lt; 20%).
                     </p>
                     <button className="mt-6 w-full py-3 bg-white text-delphi-orange rounded-xl text-[10px] font-black uppercase tracking-[0.2em] shadow-sm hover:scale-[1.02] transition-all">
                       Alertar Expertos
                     </button>
                  </div>
                  <TrendingUp className="absolute -bottom-6 -right-6 w-32 h-32 text-delphi-orange/10 -rotate-12 group-hover:scale-125 transition-transform" />
                </div>
              )}
            </div>

            <div className="lg:col-span-8 space-y-10">
              {currentTask ? (
                <EstimationRounds taskId={currentTask.id} taskTitle={currentTask.title} unit="Horas" />
              ) : (
                <div className="h-96 bg-white rounded-[3rem] border-4 border-dashed border-slate-100 flex flex-col items-center justify-center text-slate-200 gap-6">
                  <Star className="w-20 h-20 opacity-20" />
                  <p className="font-black text-2xl tracking-tight text-slate-300">Seleccione una tarea para analizar</p>
                </div>
              )}
            </div>
          </>
        )}

        {activeTab === 'docs' && (
          <div className="lg:col-span-12">
            <Documentation projectId={projectId} />
          </div>
        )}

        {activeTab === 'discussion' && (
          <div className="lg:col-span-12">
            <DiscussionSpace />
          </div>
        )}

        {activeTab === 'team' && (
          <div className="lg:col-span-12">
            <TeamPanel />
          </div>
        )}
      </div>
    </div>
  );
};

