        )}

        {activeTab === 'discussion' && (
          <div className="lg:col-span-12">
            <DiscussionSpace />
          </div>
        )}

        {activeTab === 'team' && (
          <div className="lg:col-span-12">
            <TeamPanel />
          </div>
        )}

        {activeTab === 'audit' && (
          <div className="lg:col-span-12">
            <ProjectAuditLog entries={MOCK_AUDIT} />
          </div>
        )}
      </div>
    </div>
  );
};

