              {isAnalyzing ? (
                <div className="flex flex-col items-center justify-center py-12 gap-4">
                   <Sparkles className="w-12 h-12 text-delphi-keppel animate-pulse" />
                   <p className="font-black text-slate-900 text-lg">Gemini Pro analizando consenso...</p>
