                        <BrainCircuit className="w-6 h-6 text-delphi-keppel" />
                        Análisis AI
                      </h4>
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                        analysis.level === 'Alta' ? 'bg-delphi-celadon/20 text-delphi-keppel' :
                        analysis.level === 'Media' ? 'bg-delphi-vanilla text-delphi-orange' : 'bg-delphi-giants/10 text-delphi-giants'
                      }`}>
                        Convergencia {analysis.level}
                      </span>
                   </div>
                   <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                      <p className="text-sm font-black text-slate-900 mb-2">Recomendación:</p>
                      <p className="text-sm text-slate-600 font-bold leading-relaxed">{analysis.recommendation}</p>
