                   <div className="space-y-2">
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest ml-2">Insights Técnicos</p>
                      <p className="text-sm text-slate-600 leading-relaxed font-medium bg-delphi-keppel/5 p-6 rounded-[2rem] border border-delphi-keppel/10">
                        {analysis.aiInsights}
                      </p>
                   </div>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-12 text-slate-300 italic text-sm">
                   Cierra la ronda para ver el análisis de convergencia.
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

