                                  <span className="text-[9px] font-black text-delphi-keppel uppercase tracking-widest">{task.status === 'Estimando' ? 'Iterando' : 'En cola'}</span>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
